class Solution {
public:
    vector<int> shortestAlternatingPaths(int n, vector<vector<int>>& redEdges, vector<vector<int>>& blueEdges) {
        vector<vector<pair<int,int>>> g(n);
        for (auto& e : redEdges)  g[e[0]].emplace_back(e[1], 0);
        for (auto& e : blueEdges) g[e[0]].emplace_back(e[1], 1);

        vector<int> ans(n, -1);
        vector<vector<int>> dist(n, vector<int>(2, -1));
        queue<pair<int,int>> q;
        dist[0][0] = dist[0][1] = 0;
        q.emplace(0, 0);
        q.emplace(0, 1);

        while (!q.empty()) {
            auto [u, c] = q.front(); q.pop();
            for (auto [v, nc] : g[u]) {
                if (nc != c || dist[v][nc] != -1) continue;
                dist[v][nc] = dist[u][c] + 1;
                q.emplace(v, nc);
            }
        }

        for (int i = 0; i < n; ++i) {
            int d = dist[i][0];
            if (dist[i][1] != -1 && (d == -1 || dist[i][1] < d)) d = dist[i][1];
            ans[i] = (d == -1) ? -1 : d;
        }
        return ans;
    }
};
